# Secure HTTP Headers — Nginx configuration example
server {
    listen 443 ssl;
    server_name example.com;

    # Force HTTPS for 1 year, include subdomains, preload
    add_header Strict-Transport-Security \
        "max-age=31536000; includeSubDomains; preload" always;

    # Prevent XSS by whitelisting content sources
    add_header Content-Security-Policy \
        "default-src 'self'; script-src 'self' 'nonce-{RANDOM}'; \
         style-src 'self'; img-src 'self' data:; \
         frame-ancestors 'none'" always;

    # Prevent clickjacking
    add_header X-Frame-Options "DENY" always;

    # Prevent MIME type sniffing
    add_header X-Content-Type-Options "nosniff" always;

    # Control referrer information
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;

    # Permissions policy (disable unused browser features)
    add_header Permissions-Policy \
        "camera=(), microphone=(), geolocation=()" always;
}
